def test_layernorm_configs(B, T, D, eps, seed):
    torch.manual_seed(seed)
    norm = nn.LayerNorm(D, eps=eps)
    x = torch.randn(B, T, D)
    out = norm(x)
    assert out.shape == (B, T, D)
