def test_ffn_configs(B, T, D, mult, act, seed):
    torch.manual_seed(seed)
    ACT = {'gelu': nn.GELU(), 'relu': nn.ReLU(), 'silu': nn.SiLU()}
    ffn = nn.Sequential(nn.Linear(D, D*mult), ACT[act], nn.Linear(D*mult, D))
    x = torch.randn(B, T, D)
    out = ffn(x)
    assert out.shape == (B, T, D)

