def test_dropout_configs(B, T, D, p, seed):
    torch.manual_seed(seed)
    drop = nn.Dropout(p=p)
    x = torch.randn(B, T, D)
    drop.eval()
    out = drop(x)
    assert torch.allclose(out, x)
